Changes:
Replace the url handling block to expect `Record<string, string>`:
```ts
if (definition.type === 'url') {
  if (typeof rawValue !== 'object' || rawValue === null || Array.isArray(rawValue)) {
    log.warn(`Plugin "${pluginName}" setting "${key}": expected a Record<string, string>, got ${typeof rawValue} — skipping`);
    continue;
  }
  const urlMap = rawValue as Record<string, string>;
  const validEntries: Record<string, string> = {};
  for (const [instanceName, url] of Object.entries(urlMap)) {
    if (typeof url !== 'string' || url.length === 0) {
      log.warn(`Plugin "${pluginName}" setting "${key}" instance "${instanceName}": expected a URL string — skipping`);
      continue;
    }
    const pattern = deriveMatchPattern(url);
    if (!pattern) {
      log.warn(`Plugin "${pluginName}" setting "${key}" instance "${instanceName}": invalid URL "${url}" — skipping`);
      continue;
    }
    derivedPatterns.push(pattern);
    validEntries[instanceName] = pattern;
    if (!derivedHomepage) derivedHomepage = url;
  }
  if (Object.keys(validEntries).length > 0) {
    instanceMap = { ...instanceMap, ...validEntries };
    resolvedValues[key] = rawValue; // Store the full map — needed for per-tab config injection
  }
}
```

Add `instanceMap` to ResolvedSettings interface:
```ts
interface ResolvedSettings {
  effectiveUrlPatterns: string[];
  effectiveHomepage: string | undefined;
  resolvedValues: Record<string, unknown>; // Changed from Record<string, string | number | boolean> to support url maps
  instanceMap: Record<string, string>; // instance name → match pattern
}
```

Note: `resolvedValues` type needs to widen to `Record<string, unknown>` since url fields now store `Record<string, string>` instead of `string`. This type change will ripple to `RegisteredPlugin.resolvedSettings` in state.ts and `ConfigStatePlugin.resolvedSettings` in shared/src/index.ts. The worker should update those types too.

Update existing tests to use the new map format and add tests for:
- Single-instance map: `{ instanceUrl: { production: 'https://prod.example.com' } }` → 1 pattern, instanceMap has 1 entry
- Multi-instance map: `{ instanceUrl: { production: '...', staging: '...' } }` → 2 patterns, instanceMap has 2 entries
- Mixed valid/invalid URLs in map
- Empty map
- Non-object url value (should warn and skip)

Constraints:
- deriveMatchPattern function is unchanged
- Non-url field handling is unchanged
- The resolvedValues for url fields stores the raw Record<string, string> from config (the URL values, not the patterns)

