```ts
// Resolve per-tab settings: for url fields, replace the Record<string, string> map
// with the single URL value matching this tab's instance
const resolvePerTabSettings = (
  settings: Record<string, unknown>,
  instanceMap: Record<string, string> | undefined,
  tabUrl: string,
): Record<string, string | number | boolean> => {
  if (!instanceMap) return settings as Record<string, string | number | boolean>;
  const resolved: Record<string, string | number | boolean> = {};
  let matchedInstance: string | undefined;
  // Find which instance this tab belongs to
  try {
    const tabHost = new URL(tabUrl).hostname;
    for (const [name, pattern] of Object.entries(instanceMap)) {
      const patternHost = pattern.replace('*://', '').replace('/*', '');
      if (tabHost === patternHost) {
        matchedInstance = name;
        break;
      }
    }
  } catch {}
  for (const [key, value] of Object.entries(settings)) {
    if (typeof value === 'object' && value !== null && !Array.isArray(value) && matchedInstance) {
      // url-type field stored as Record<string, string> — resolve to this instance's URL
      const urlMap = value as Record<string, string>;
      resolved[key] = urlMap[matchedInstance] ?? '';
    } else if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
      resolved[key] = value;
    }
  }
  return resolved;
};
```

4. Call this resolver before injectPluginConfig, passing the tab's URL (available from chrome.tabs.get or the URL pattern matching context).

The tab URL is available in the injection context — injectIntoMatchingTabs gets tabs via chrome.tabs.query and each tab has a url property.

Constraints:
